    || (CASE WHEN country_config ? 'datetime.weekend_days' THEN '{}'::jsonb
             ELSE jsonb_build_object('datetime.weekend_days', '[6,0]'::jsonb) END)
    || (CASE WHEN country_config ? 'datetime.week_starts_on' THEN '{}'::jsonb
             ELSE jsonb_build_object('datetime.week_starts_on', 0) END)
WHERE code = 'VI' AND deleted_at IS NULL;

